content:
[
  {
    "name": "echo-text",
    "description": "Echo text to stdout",
    "command": "echo $text",
    "parameters": [
      { "name": "text", "description": "the text to show" }
    ]
  },
  {
    "name": "geolocation",
    "description": "Get current location based on internet connection",
    "command": "python tools/geolocation.py",
    "parameters": []
  },
  {
    "name": "weather",
    "description": "Get current weather for a location via wttr.in",
    "command": "python tools/weather.py $location 2",
    "parameters": [
      { "name": "location", "description": "City or place name" }
    ]
  },
  {
    "name": "weather-full",
    "description": "Get full weather report for a location",
    "command": "python tools/weather.py $location",
    "parameters": [
      { "name": "location", "description": "City or place name" }
    ]
  },
  {
    "name": "spotify-auth",
    "description": "Authenticate with Spotify account (run once to setup)",
    "command": "python tools/spotify.py auth",
    "parameters": []
  },
  {
    "name": "spotify-status",
    "description": "Get current Spotify playback status",
    "command": "python tools/spotify.py status",
    "parameters": []
  },
  {
    "name": "spotify-play",
    "description": "Play music - optionally search and play a track",
    "command": "python tools/spotify.py play $query",
    "parameters": [
      { "name": "query", "description": "Song/artist/album to search and play (optional)" }
    ]
  },
  {
    "name": "spotify-play-device",
    "description": "Search and play a track on a specific device",
    "command": "python tools/spotify.py play $query --device $device_id",
    "parameters": [
      { "name": "query", "description": "Song/artist/album to search and play" },
      { "name": "device_id", "description": "Device ID to play on (get from spotify-devices command)" }
    ]
  },
  {
    "name": "spotify-pause",
    "description": "Pause Spotify playback",
    "command": "python tools/spotify.py pause",
    "parameters": []
  },
  {
    "name": "spotify-next",
    "description": "Skip to next track",
    "command": "python tools/spotify.py next",
    "parameters": []
  },
  {
    "name": "spotify-prev",
    "description": "Go to previous track",
    "command": "python tools/spotify.py prev",
    "parameters": []
  },
  {
    "name": "spotify-volume",
    "description": "Set Spotify volume (0-100)",
    "command": "python tools/spotify.py volume $level",
    "parameters": [
      { "name": "level", "description": "Volume level 0-100" }
    ]
  },
  {
    "name": "spotify-search",
    "description": "Search for tracks, artists, albums on Spotify",
    "command": "python tools/spotify.py search $query",
    "parameters": [
      { "name": "query", "description": "Search query (song, artist, or album)" }
    ]
  },
  {
    "name": "spotify-queue",
    "description": "Add a track to the playback queue",
    "command": "python tools/spotify.py queue $query",
    "parameters": [
      { "name": "query", "description": "Song/artist/album to add to queue" }
    ]
  },
  {
    "name": "spotify-devices",
    "description": "List available Spotify playback devices",
    "command": "python tools/spotify.py devices",
    "parameters": []
  }
]

